{
  "name": "Djimtech - Coach & Formateur IA",
  "description": "Landing page professionnelle pour Djimi Adotevi, expert en IA, présentant un parcours de formation progressif en 3 niveaux : Chatbots, Agents IA et Vibe Coding."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useEffect } from 'react';
import { 
  Bot, 
  Cpu, 
  Zap, 
  CheckCircle2, 
  Users, 
  ArrowRight, 
  ShieldCheck, 
  Lightbulb, 
  GraduationCap, 
  BrainCircuit,
  Menu,
  X,
  ChevronRight,
  Code2,
  Sparkles,
  Layers,
  Target
} from 'lucide-react';

// --- Types ---

interface LevelProps {
  number: number;
  title: string;
  objective: string;
  items: string[];
  tools?: string[];
  cta: string;
  color: string;
}

// --- Helper Components ---

const Navbar = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 20);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const navLinks = [
    { name: 'Approche', href: '#approche' },
    { name: 'Parcours', href: '#parcours' },
    { name: 'Le Coach', href: '#coach' },
    { name: 'Publics', href: '#publics' },
  ];

  return (
    <nav className={`fixed top-0 w-full z-50 transition-all duration-300 ${scrolled ? 'glass-card py-4 shadow-xl' : 'bg-transparent py-6'}`}>
      <div className="max-w-7xl mx-auto px-6 flex justify-between items-center">
        <div className="flex items-center gap-2">
          <div className="w-10 h-10 bg-gradient-to-br from-blue-500 to-purple-600 rounded-lg flex items-center justify-center font-bold text-xl">D</div>
          <span className="text-xl font-bold tracking-tight font-outfit">DJIMTECH</span>
        </div>

        {/* Desktop Menu */}
        <div className="hidden md:flex items-center gap-8">
          {navLinks.map((link) => (
            <a key={link.name} href={link.href} className="text-sm font-medium text-gray-400 hover:text-white transition-colors">{link.name}</a>
          ))}
          <button className="bg-white text-black px-6 py-2.5 rounded-full text-sm font-bold hover:bg-gray-200 transition-all">
            Nous Contacter
          </button>
        </div>

        {/* Mobile Toggle */}
        <button className="md:hidden" onClick={() => setIsOpen(!isOpen)}>
          {isOpen ? <X /> : <Menu />}
        </button>
      </div>

      {/* Mobile Menu */}
      {isOpen && (
        <div className="md:hidden absolute top-full left-0 w-full glass-card p-6 flex flex-col gap-4 animate-in fade-in slide-in-from-top-4">
          {navLinks.map((link) => (
            <a key={link.name} href={link.href} onClick={() => setIsOpen(false)} className="text-lg font-medium py-2 border-b border-white/5">{link.name}</a>
          ))}
          <button className="w-full bg-white text-black py-4 rounded-xl font-bold mt-4">
            Demander une formation
          </button>
        </div>
      )}
    </nav>
  );
};

const SectionHeader = ({ title, subtitle, centered = true }: { title: string, subtitle?: string, centered?: boolean }) => (
  <div className={`mb-16 ${centered ? 'text-center' : ''}`}>
    <h2 className="text-3xl md:text-5xl font-bold mb-4 font-outfit leading-tight">{title}</h2>
    {subtitle && <p className="text-xl text-gray-400 max-w-2xl mx-auto">{subtitle}</p>}
  </div>
);

const LevelCard = ({ number, title, objective, items, tools, cta, color }: LevelProps) => (
  <div className="relative group">
    <div className={`absolute -inset-0.5 bg-gradient-to-r ${color} rounded-2xl opacity-20 group-hover:opacity-100 transition duration-500 blur`}></div>
    <div className="relative glass-card p-8 rounded-2xl h-full flex flex-col">
      <div className={`inline-flex items-center justify-center w-12 h-12 rounded-xl mb-6 bg-gradient-to-br ${color} font-bold text-xl`}>
        {number}
      </div>
      <h3 className="text-2xl font-bold mb-2 font-outfit uppercase tracking-wider">Niveau {number}</h3>
      <h4 className="text-xl font-semibold mb-6 text-white">{title}</h4>

      <div className="mb-6">
        <span className="text-xs font-bold text-gray-500 uppercase tracking-widest block mb-2">Objectif</span>
        <p className="text-gray-300 leading-relaxed">{objective}</p>
      </div>

      <div className="flex-grow space-y-3 mb-8">
        {items.map((item, idx) => (
          <div key={idx} className="flex items-start gap-3">
            <CheckCircle2 className="w-5 h-5 text-green-400 shrink-0 mt-0.5" />
            <span className="text-sm text-gray-300">{item}</span>
          </div>
        ))}
      </div>

      {tools && (
        <div className="mb-8">
          <span className="text-xs font-bold text-gray-500 uppercase tracking-widest block mb-3">Outils clés</span>
          <div className="flex flex-wrap gap-2">
            {tools.map(tool => (
              <span key={tool} className="px-3 py-1 bg-white/5 rounded-full text-xs text-gray-400 border border-white/10">{tool}</span>
            ))}
          </div>
        </div>
      )}

      <button className="group/btn flex items-center justify-center gap-2 w-full py-4 px-6 rounded-xl bg-white/5 hover:bg-white/10 border border-white/10 transition-all text-sm font-bold">
        {cta}
        <ChevronRight className="w-4 h-4 group-hover/btn:translate-x-1 transition-transform" />
      </button>
    </div>
  </div>
);

// --- Main Components ---

const Hero = () => (
  <section className="relative pt-32 pb-20 md:pt-48 md:pb-32 px-6 overflow-hidden">
    <div className="absolute top-0 left-1/2 -translate-x-1/2 w-full h-[600px] bg-gradient-to-b from-blue-500/10 via-purple-500/5 to-transparent blur-3xl pointer-events-none"></div>
    <div className="max-w-7xl mx-auto relative z-10 text-center">
      <div className="inline-flex items-center gap-2 px-4 py-2 rounded-full bg-blue-500/10 border border-blue-500/20 text-blue-400 text-sm font-bold mb-8 animate-bounce">
        <Sparkles className="w-4 h-4" />
        Formation & Accompagnement IA 2025
      </div>
      <h1 className="text-5xl md:text-8xl font-bold mb-8 leading-tight tracking-tight font-outfit">
        Coach & Formateur en <br />
        <span className="text-gradient">Intelligence Artificielle</span>
      </h1>
      <p className="text-xl md:text-2xl text-gray-400 mb-6 font-medium">
        Chatbots · Agents IA · Vibe Coding
      </p>
      <p className="text-lg md:text-xl text-gray-300 max-w-3xl mx-auto mb-12 leading-relaxed">
        J’accompagne individus, équipes et organisations à comprendre, maîtriser et utiliser concrètement l’IA — des chatbots aux agents autonomes, jusqu’au développement assisté par agents.
      </p>

      <div className="flex flex-col sm:flex-row items-center justify-center gap-4">
        <button className="w-full sm:w-auto px-8 py-5 bg-blue-600 hover:bg-blue-700 text-white rounded-2xl font-bold text-lg shadow-lg shadow-blue-500/25 transition-all flex items-center justify-center gap-3">
          Demander une formation IA
          <ArrowRight className="w-5 h-5" />
        </button>
        <button className="w-full sm:w-auto px-8 py-5 glass-card hover:bg-white/10 text-white rounded-2xl font-bold text-lg transition-all">
          Être accompagné
        </button>
      </div>
    </div>
  </section>
);

const Philosophy = () => {
  const points = [
    { icon: <Layers className="text-blue-400" />, title: "Approche progressive", desc: "Un apprentissage structuré qui vous emmène du simple usage quotidien au pilotage complexe de systèmes." },
    { icon: <ShieldCheck className="text-purple-400" />, title: "Orientation autonomie", desc: "Comprendre les fondamentaux avant d'utiliser les outils pour ne jamais être dépendant de la technologie." },
    { icon: <Zap className="text-pink-400" />, title: "Apprentissage pratique", desc: "Pas de théorie inutile. 80% du temps est consacré à la manipulation réelle des outils sur vos cas d'usage." },
    { icon: <BrainCircuit className="text-indigo-400" />, title: "IA Responsable", desc: "Intégrer l'intelligence artificielle de manière éthique, utile et maîtrisée au sein de vos processus." }
  ];

  return (
    <section id="approche" className="py-24 px-6 bg-white/[0.02]">
