        <div className="grid md:grid-cols-2 lg:grid-cols-4 gap-8">
          {points.map((p, i) => (
            <div key={i} className="glass-card p-8 rounded-3xl hover:translate-y-[-4px] transition-all duration-300">
              <div className="w-14 h-14 bg-white/5 rounded-2xl flex items-center justify-center mb-6">{p.icon}</div>
              <h3 className="text-xl font-bold mb-4 font-outfit">{p.title}</h3>
              <p className="text-gray-400 leading-relaxed">{p.desc}</p>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
};

const Levels = () => {
  const levels: LevelProps[] = [
    {
      number: 1,
      title: "Maîtrise des Chatbots",
      objective: "Rendre l’utilisateur autonome et stratégique dans l’usage des chatbots IA.",
      items: [
        "Comprendre comment fonctionnent les LLMs",
        "Apprendre à bien formuler ses prompts",
        "Choisir le bon outil selon le besoin spécifique",
