      ],
      tools: ["Make", "Zapier", "LangChain", "n8n", "OpenAI Assistants"],
      cta: "Mettre en place des agents IA",
      color: "from-purple-600 to-indigo-400"
    },
    {
      number: 3,
      title: "Vibe Coding & Agents",
      objective: "Créer, coder et prototyper plus vite grâce à la collaboration humain–agent.",
      items: [
        "Comprendre le concept de Vibe Coding",
        "Collaboration fluide humain–agent",
        "Développement assisté par agents",
        "Prototypage ultra-rapide d'applications"
      ],
      tools: ["Cursor", "Replit", "Windsurf", "Claude Dev", "v0.dev"],
      cta: "Apprendre le vibe coding",
      color: "from-pink-500 to-orange-400"
    }
  ];

  return (
    <section id="parcours" className="py-24 px-6 relative overflow-hidden">
      {/* Visual background accents */}
      <div className="absolute top-1/2 left-0 w-96 h-96 bg-blue-600/10 rounded-full blur-[120px] -translate-x-1/2 -translate-y-1/2"></div>
      <div className="absolute bottom-0 right-0 w-96 h-96 bg-purple-600/10 rounded-full blur-[120px] translate-x-1/2 translate-y-1/2"></div>

      <div className="max-w-7xl mx-auto relative z-10">
        <SectionHeader 
          title="Le Parcours de Montée en Compétence" 
          subtitle="Une progression logique pour passer de spectateur à créateur de solutions IA." 
        />
        <div className="grid lg:grid-cols-3 gap-8">
          {levels.map((level) => (
            <LevelCard key={level.number} {...level} />
          ))}
        </div>
      </div>
