import React, { useState, useEffect } from 'react';
import { 
  Bot, 
  Cpu, 
  Zap, 
  CheckCircle2, 
  Users, 
  ArrowRight, 
  ShieldCheck, 
  Lightbulb, 
  GraduationCap, 
  BrainCircuit,
  Menu,
  X,
  ChevronRight,
  Code2,
  Sparkles,
  Layers,
  Target
} from 'lucide-react';

// --- Types ---

// Added key property to resolve TypeScript error when spreading props in Levels component
interface LevelProps {
  number: number;
  title: string;
  objective: string;
  items: string[];
  tools?: string[];
  cta: string;
  color: string;
  key?: React.Key;
}

// --- Helper Components ---

const Navbar = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 20);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const navLinks = [
    { name: 'Approche', href: '#approche' },
    { name: 'Parcours', href: '#parcours' },
    { name: 'Le Coach', href: '#coach' },
    { name: 'Publics', href: '#publics' },
  ];

  return (
    <nav className={`fixed top-0 w-full z-50 transition-all duration-300 ${scrolled ? 'glass-card py-4 shadow-xl' : 'bg-transparent py-6'}`}>
      <div className="max-w-7xl mx-auto px-6 flex justify-between items-center">
        <div className="flex items-center gap-2">
          <div className="w-10 h-10 bg-gradient-to-br from-blue-500 to-purple-600 rounded-lg flex items-center justify-center font-bold text-xl">D</div>
          <span className="text-xl font-bold tracking-tight font-outfit">DJIMTECH</span>
        </div>

        {/* Desktop Menu */}
        <div className="hidden md:flex items-center gap-8">
          {navLinks.map((link) => (
            <a key={link.name} href={link.href} className="text-sm font-medium text-gray-400 hover:text-white transition-colors">{link.name}</a>
          ))}
          <button className="bg-white text-black px-6 py-2.5 rounded-full text-sm font-bold hover:bg-gray-200 transition-all">
            Nous Contacter
          </button>
        </div>

        {/* Mobile Toggle */}
        <button className="md:hidden" onClick={() => setIsOpen(!isOpen)}>
          {isOpen ? <X /> : <Menu />}
        </button>
      </div>

      {/* Mobile Menu */}
      {isOpen && (
        <div className="md:hidden absolute top-full left-0 w-full glass-card p-6 flex flex-col gap-4 animate-in fade-in slide-in-from-top-4">
          {navLinks.map((link) => (
